(()=>{document.querySelector("[data-hubspot]").addEventListener("submit",async function(o){o.preventDefault();let t=o.target,s=new FormData(t),r=t.querySelector('input[name="consent"]');if(document.querySelectorAll("[data-hubspot-message] > div").forEach(e=>e.classList.add("hidden")),!r.checked){document.querySelector("[data-hubspot-consent-error]").classList.remove("hidden");return}let a={fields:Array.from(s.entries()).map(([e,n])=>({name:e,value:n}))};try{let e=await fetch("https://api-eu1.hsforms.com/submissions/v3/integration/submit/143630396/b7e64c0d-fc4b-4940-bad4-adbf03471f8f",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(a)});document.querySelector(e.ok?"[data-hubspot-success]":"[data-hubspot-error]").classList.remove("hidden"),e.ok&&t.reset()}catch{document.querySelector("[data-hubspot-error]").classList.remove("hidden")}});})();